mapper.select:
SELECT gr.record_id AS recordId, gr.student_id AS studentId, stu.real_name AS studentName, stu.username AS studentNo, stu.user_phone AS studentPhone, stu.user_email AS studentEmail, gr.teacher_id AS teacherId, tea.real_name AS teacherName, gr.topic_id AS topicId, t.topic_title AS topicTitle, gr.guidance_type AS guidanceType, CASE gr.guidance_type WHEN 1 THEN '项目指导' WHEN 2 THEN '论文指导' ELSE '未知' END AS guidanceTypeDesc, DATE_FORMAT(gr.guidance_date, '%Y-%m-%d') AS guidanceDate, gr.guidance_method AS guidanceMethod, gr.duration_hours AS durationHours, LEFT(gr.guidance_content, 100) AS contentSummary, DATE_FORMAT(gr.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM guidance_record gr LEFT JOIN user_info stu ON gr.student_id = stu.user_id LEFT JOIN user_info tea ON gr.teacher_id = tea.user_id LEFT JOIN topic_info t ON gr.topic_id = t.topic_id WHERE gr.student_id = #{studentId} AND gr.deleted = 0
AND gr.guidance_type = #{guidanceType}
ORDER BY gr.guidance_date DESC, gr.create_time DESC

SELECT ts.student_id AS studentId, stu.real_name AS studentName, stu.username AS studentNo, stu.user_phone AS studentPhone, stu.user_email AS studentEmail, ts.topic_id AS topicId, t.topic_title AS topicTitle, IFNULL(stat.record_count, 0) AS recordCount, DATE_FORMAT(stat.last_date, '%Y-%m-%d') AS lastGuidanceDate, IFNULL(CAST(stat.total_hours AS CHAR), '0') AS totalHours FROM topic_selection ts INNER JOIN topic_info t ON ts.topic_id = t.topic_id INNER JOIN user_info stu ON ts.student_id = stu.user_id LEFT JOIN ( SELECT student_id, COUNT(*) AS record_count, MAX(guidance_date) AS last_date, SUM(IFNULL(duration_hours, 0)) AS total_hours FROM guidance_record WHERE teacher_id = #{teacherId} AND deleted = 0
AND guidance_type = #{guidanceType}
GROUP BY student_id ) stat ON ts.student_id = stat.student_id WHERE t.creator_id = #{teacherId} AND ts.selection_status = 1 AND ts.deleted = 0 ORDER BY ISNULL(stat.last_date), stat.last_date DESC, stu.real_name ASC

SELECT gr.record_id AS recordId, gr.student_id AS studentId, stu.real_name AS studentName, stu.username AS studentNo, stu.user_phone AS studentPhone, stu.user_email AS studentEmail, gr.teacher_id AS teacherId, tea.real_name AS teacherName, gr.topic_id AS topicId, t.topic_title AS topicTitle, gr.guidance_type AS guidanceType, CASE gr.guidance_type WHEN 1 THEN '项目指导' WHEN 2 THEN '论文指导' ELSE '未知' END AS guidanceTypeDesc, DATE_FORMAT(gr.guidance_date, '%Y-%m-%d') AS guidanceDate, gr.guidance_method AS guidanceMethod, gr.duration_hours AS durationHours, LEFT(gr.guidance_content, 100) AS contentSummary, DATE_FORMAT(gr.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM guidance_record gr INNER JOIN topic_info t ON gr.topic_id = t.topic_id LEFT JOIN user_info stu ON gr.student_id = stu.user_id LEFT JOIN user_info tea ON gr.teacher_id = tea.user_id WHERE t.enterprise_id = #{enterpriseId} AND gr.deleted = 0
AND stu.real_name LIKE CONCAT('%', #{studentName}, '%')
AND gr.teacher_id = #{teacherId}
AND gr.guidance_type = #{guidanceType}
AND gr.guidance_date >= #{startDate}
AND gr.guidance_date <= #{endDate}
ORDER BY gr.guidance_date DESC, gr.create_time DESC

SELECT gr.record_id AS recordId, gr.student_id AS studentId, stu.real_name AS studentName, stu.username AS studentNo, stu.user_phone AS studentPhone, stu.user_email AS studentEmail, gr.teacher_id AS teacherId, tea.real_name AS teacherName, gr.topic_id AS topicId, t.topic_title AS topicTitle, gr.guidance_type AS guidanceType, CASE gr.guidance_type WHEN 1 THEN '项目指导' WHEN 2 THEN '论文指导' ELSE '未知' END AS guidanceTypeDesc, DATE_FORMAT(gr.guidance_date, '%Y-%m-%d') AS guidanceDate, gr.guidance_method AS guidanceMethod, gr.duration_hours AS durationHours, LEFT(gr.guidance_content, 100) AS contentSummary, DATE_FORMAT(gr.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM guidance_record gr INNER JOIN topic_info t ON gr.topic_id = t.topic_id INNER JOIN teacher_relationship tr ON t.creator_id = tr.enterprise_teacher_id LEFT JOIN user_info stu ON gr.student_id = stu.user_id LEFT JOIN user_info tea ON gr.teacher_id = tea.user_id WHERE tr.univ_teacher_id = #{univTeacherId} AND tr.is_enabled = 1 AND tr.deleted = 0 AND gr.deleted = 0
AND gr.guidance_type = #{guidanceType}
ORDER BY gr.guidance_date DESC, gr.create_time DESC
